import torch
import torch.nn as nn
from torch.utils.cpp_extension import load_inline

# Define custom CUDA kernel for optimized matrix multiplication
matmul_source = """
#include <torch/extension.h>
#include <cuda_runtime.h>
#include <cublas_v2.h>

// Tile size for shared memory optimization
#define TILE_SIZE 32

__global__ void matmul_kernel(const float* A, const float* B, float* C, 
                              int M, int N, int K) {
    // Shared memory for tiles
    __shared__ float As[TILE_SIZE][TILE_SIZE];
    __shared__ float Bs[TILE_SIZE][TILE_SIZE];

    // Compute thread positions once
    const int thread_row = threadIdx.y;
    const int thread_col = threadIdx.x;
    const int block_row = blockIdx.y;
    const int block_col = blockIdx.x;

    // Compute global positions with explicit bounds checking
    const int global_row = block_row * TILE_SIZE + thread_row;
    const int global_col = block_col * TILE_SIZE + thread_col;

    float sum = 0.0f;

    // Loop over tiles
    for (int t = 0; t < (K + TILE_SIZE - 1) / TILE_SIZE; ++t) {
        // Compute indices with explicit bounds checking
        const int a_col_idx = t * TILE_SIZE + thread_col;
        const int b_row_idx = t * TILE_SIZE + thread_row;

        // Load tile from A with proper bounds checking
        if (global_row < M && a_col_idx < K) {
            As[thread_row][thread_col] = A[global_row * K + a_col_idx];
        } else {
            As[thread_row][thread_col] = 0.0f;
        }

        // Load tile from B (transposed) with proper bounds checking
        if (global_col < N && b_row_idx < K) {
            Bs[thread_row][thread_col] = B[global_col * K + b_row_idx];
        } else {
            Bs[thread_row][thread_col] = 0.0f;
        }

        __syncthreads();

        // Compute partial sum
        #pragma unroll
        for (int k = 0; k < TILE_SIZE; ++k) {
            sum += As[thread_row][k] * Bs[k][thread_col];
        }

        __syncthreads();
    }

    // Write result with explicit bounds checking
    if (global_row < M && global_col < N) {
        C[global_row * N + global_col] = sum;
    }
}

torch::Tensor matmul_cuda(torch::Tensor A, torch::Tensor B) {
    // Validate dimensions
    TORCH_CHECK(A.dim() == 2, "A must be 2D");
    TORCH_CHECK(B.dim() == 2, "B must be 2D");
    TORCH_CHECK(A.size(1) == B.size(1), "Inner dimensions must match");

    // Get dimensions
    int M = A.size(0);
    int K = A.size(1);
    int N = B.size(0);

    // Create output tensor
    auto C = torch::zeros({M, N}, A.options());

    // Configure kernel launch parameters
    dim3 blockDim(TILE_SIZE, TILE_SIZE);
    dim3 gridDim((N + TILE_SIZE - 1) / TILE_SIZE, 
                 (M + TILE_SIZE - 1) / TILE_SIZE);

    // Launch kernel with error checking
    cudaError_t err = cudaGetLastError();
    matmul_kernel<<<gridDim, blockDim>>>(
        A.data_ptr<float>(),
        B.data_ptr<float>(),
        C.data_ptr<float>(),
        M, N, K
    );
    err = cudaGetLastError();
    TORCH_CHECK(err == cudaSuccess, 
                "CUDA kernel launch failed: ", cudaGetErrorString(err));

    return C;
}
"""

matmul_cpp_source = "torch::Tensor matmul_cuda(torch::Tensor A, torch::Tensor B);"

# Compile the inline CUDA code
matmul_cuda = load_inline(
    name="matmul_cuda",
    cpp_sources=matmul_cpp_source,
    cuda_sources=matmul_source,
    functions=["matmul_cuda"],
    verbose=False,
    extra_cflags=["-O3"],
    extra_ldflags=["-lcublas"],
)

class ModelNew(nn.Module):
    """
    Optimized model with custom CUDA kernel for matrix multiplication
    """
    def __init__(self):
        super(ModelNew, self).__init__()
        self.matmul_cuda = matmul_cuda

    def forward(self, A: torch.Tensor, B: torch.Tensor) -> torch.Tensor:
        """
        Performs optimized matrix multiplication using custom CUDA kernel.

        Args:
            A: Input tensor of shape (M, K).
            B: Input tensor of shape (N, K).

        Returns:
            Output tensor of shape (M, N).
        """
        return self.matmul_cuda.matmul_cuda(A, B)
